class Solution {
public:
    string robotWithString(string s) {
        string t = "", p = "";
        while (!s.empty() || !t.empty()) {
            if (t.empty()) {
                t += s[0];
                s.erase(s.begin());
            } else if (s.empty() || t.back() <= s[0]) {
                p += t.back();
                t.pop_back();
            } else {
                t += s[0];
                s.erase(s.begin());
            }
        }
        return p;
    }
};

